package github.chains;

import com.github.javaparser.StaticJavaParser;
import com.github.javaparser.ast.CompilationUnit;
import com.github.javaparser.ast.ImportDeclaration;
import java.io.File;
import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;
import java.util.ArrayList;
import java.util.HashMap;
import java.util.List;
import java.util.Map;
import java.util.stream.Stream;

/**
 * JavaParser transformation to fix cactoos import errors.
 * Fixes incorrect package paths for cactoos classes.
 */
public class Main {

    private static final Map<String, String> IMPORT_FIXES = new HashMap<>();

    static {
        // Fix collection package imports to iterable/list packages
        IMPORT_FIXES.put("org.cactoos.collection.Filtered", "org.cactoos.iterable.Filtered");
        IMPORT_FIXES.put("org.cactoos.collection.CollectionOf", "org.cactoos.list.CollectionOf");
        // Fix text class names (removed "Text" suffix)
        IMPORT_FIXES.put("org.cactoos.text.SplitText", "org.cactoos.text.Split");
        IMPORT_FIXES.put("org.cactoos.text.JoinedText", "org.cactoos.text.Joined");
        IMPORT_FIXES.put("org.cactoos.text.TrimmedText", "org.cactoos.text.Trimmed");
        // Fix scalar class names
        IMPORT_FIXES.put("org.cactoos.scalar.StickyScalar", "org.cactoos.scalar.Sticky");
        IMPORT_FIXES.put("org.cactoos.scalar.SolidScalar", "org.cactoos.scalar.Sticky");
        // Fix scalar package for IoCheckedScalar
        IMPORT_FIXES.put("org.cactoos.scalar.IoCheckedScalar", "org.cactoos.func.IoCheckedScalar");
    }

    public static void main(String[] args) throws IOException {
        if (args.length < 1) {
            System.err.println("Usage: java github.chains.Main <source-directory>");
            System.exit(1);
        }

        Path sourceDir = Paths.get(args[0]);
        if (!Files.isDirectory(sourceDir)) {
            System.err.println("Error: " + sourceDir + " is not a directory");
            System.exit(1);
        }

        System.out.println("Processing Java files in: " + sourceDir);

        try (Stream<Path> paths = Files.walk(sourceDir)) {
            List<Path> javaFiles = paths
                .filter(Files::isRegularFile)
                .filter(p -> p.toString().endsWith(".java"))
                .toList();

            int fixed = 0;
            for (Path javaFile : javaFiles) {
                if (fixImports(javaFile)) {
                    fixed++;
                    System.out.println("Fixed: " + javaFile);
                }
            }

            System.out.println("Total files fixed: " + fixed);
        }
    }

    /**
     * Fix imports in a single Java file.
     * @param javaFile Path to the Java file
     * @return true if file was modified
     */
    private static boolean fixImports(Path javaFile) throws IOException {
        String content = Files.readString(javaFile);
        boolean modified = false;
        StringBuilder result = new StringBuilder();

        String[] lines = content.split("\n", -1);
        for (String line : lines) {
            String newLine = line;
            for (Map.Entry<String, String> fix : IMPORT_FIXES.entrySet()) {
                if (line.contains("import " + fix.getKey() + ";")) {
                    newLine = line.replace(fix.getKey(), fix.getValue());
                    if (!newLine.equals(line)) {
                        modified = true;
                    }
                    break;
                }
            }
            result.append(newLine).append("\n");
        }

        if (modified) {
            Files.writeString(javaFile, result.toString());
        }

        return modified;
    }
}

