import java.util.Map;
import java.util.stream.Stream;

/**
 * JavaParser transformation to fix cactoos import errors.
 * Fixes incorrect package paths and class names for cactoos classes.
 */
public class Main {

    private static final Map<String, String> IMPORT_FIXES = new HashMap<>();
    private static final Map<String, String> CODE_FIXES = new HashMap<>();

    static {
        // Fix import statements
        IMPORT_FIXES.put("import org.cactoos.collection.Filtered;", "import org.cactoos.iterable.Filtered;");
        IMPORT_FIXES.put("import org.cactoos.collection.CollectionOf;", "// CollectionOf removed - use ArrayList instead");
        IMPORT_FIXES.put("import org.cactoos.text.SplitText;", "import org.cactoos.text.Split;");
        IMPORT_FIXES.put("import org.cactoos.text.JoinedText;", "import org.cactoos.text.Joined;");
        IMPORT_FIXES.put("import org.cactoos.text.TrimmedText;", "import org.cactoos.text.Trimmed;");
        IMPORT_FIXES.put("import org.cactoos.scalar.StickyScalar;", "import org.cactoos.scalar.Sticky;");
        IMPORT_FIXES.put("import org.cactoos.scalar.SolidScalar;", "import org.cactoos.scalar.Sticky;");
        IMPORT_FIXES.put("import org.cactoos.func.IoCheckedScalar;", "import org.cactoos.scalar.IoCheckedScalar;");
        IMPORT_FIXES.put("import org.cactoos.text.RandomText;", "import java.util.Random;");
        IMPORT_FIXES.put("import org.cactoos.scalar.CheckedScalar;", "// CheckedScalar removed - use lambda");
        IMPORT_FIXES.put("import org.cactoos.scalar.UncheckedScalar;", "// UncheckedScalar removed - use lambda");
        IMPORT_FIXES.put("import org.cactoos.iterable.LengthOf;", "// LengthOf removed - use stream count");

        // Fix code usages
        CODE_FIXES.put("new SplitText(", "new Split(");
        CODE_FIXES.put("new JoinedText(", "new Joined(");
        CODE_FIXES.put("new TrimmedText(", "new Trimmed(");
        CODE_FIXES.put("new StickyScalar<>(", "new Sticky<>(");
        CODE_FIXES.put("new SolidScalar<>(", "new Sticky<>(");
        CODE_FIXES.put("new CheckedScalar<>(", "new IoCheckedScalar<>(");
        CODE_FIXES.put("new UncheckedScalar<>(", "");
        CODE_FIXES.put("new UncheckedScalar<", "");
        CODE_FIXES.put(".value()", ".value()");
        CODE_FIXES.put("new LengthOf(", "// LengthOf replaced: (int) StreamSupport.stream(");
        CODE_FIXES.put("new RandomText()", "java.util.UUID.randomUUID().toString()");
        CODE_FIXES.put("new CollectionOf<>(", "new java.util.ArrayList<>(");
    }

    public static void main(String[] args) throws IOException {
        if (args.length < 1) {
            System.err.println("Usage: java github.chains.Main <source-directory>");
            System.exit(1);
        }

        Path sourceDir = Paths.get(args[0]);
        if (!Files.isDirectory(sourceDir)) {
            System.err.println("Error: " + sourceDir + " is not a directory");
            System.exit(1);
        }

        System.out.println("Processing Java files in: " + sourceDir);

        try (Stream<Path> paths = Files.walk(sourceDir)) {
            int fixed = 0;
            for (Path javaFile : paths.filter(Files::isRegularFile)
                    .filter(p -> p.toString().endsWith(".java")).toList()) {
                if (fixFile(javaFile)) {
                    fixed++;
                    System.out.println("Fixed: " + javaFile);
                }
            }
            System.out.println("Total files fixed: " + fixed);
        }
    }

    private static boolean fixFile(Path javaFile) throws IOException {
        String content = Files.readString(javaFile);
        String original = content;

        // Apply import fixes
        for (Map.Entry<String, String> fix : IMPORT_FIXES.entrySet()) {
            content = content.replace(fix.getKey(), fix.getValue());
        }

        // Apply code fixes
        for (Map.Entry<String, String> fix : CODE_FIXES.entrySet()) {
            content = content.replace(fix.getKey(), fix.getValue());
        }

        // Fix UncheckedScalar wrapper pattern
        content = content.replaceAll(
            "new UncheckedScalar<\\s*new ([^(]+\\([^)]*\\))\\s*\\)\\.value\\(\\)",
            "new $1.value()"
        );

        if (!content.equals(original)) {
            Files.writeString(javaFile, content);
            return true;
        }
        return false;
    }
}

package github.chains;

import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;
import java.util.stream.Stream;

/**
 * JavaParser transformation to fix cactoos import errors.
 * Only fixes imports that have direct replacements in cactoos 0.55.0.
 */
public class Main {

    public static void main(String[] args) throws IOException {
        if (args.length < 1) {
            System.err.println("Usage: java github.chains.Main <source-directory>");
            System.exit(1);
        }

        Path sourceDir = Paths.get(args[0]);
        if (!Files.isDirectory(sourceDir)) {
            System.err.println("Error: " + sourceDir + " is not a directory");
            System.exit(1);
        }

        System.out.println("Processing Java files in: " + sourceDir);

        try (Stream<Path> paths = Files.walk(sourceDir)) {
            int fixed = 0;
            for (Path javaFile : paths.filter(Files::isRegularFile)
                    .filter(p -> p.toString().endsWith(".java")).toList()) {
                if (fixFile(javaFile)) {
                    fixed++;
                    System.out.println("Fixed: " + javaFile);
                }
            }
            System.out.println("Total files fixed: " + fixed);
        }
    }

    private static boolean fixFile(Path javaFile) throws IOException {
        String content = Files.readString(javaFile);
        String original = content;

        // Fix import paths for classes that exist in cactoos 0.55.0
        content = content.replace(
            "import org.cactoos.collection.Filtered;",
            "import org.cactoos.iterable.Filtered;"
        );
