package github.chains;

import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;
import java.util.stream.Stream;

/**
 * JavaParser transformation to fix cactoos import errors for cactoos 0.55.0.
 * Fixes import paths, class names, and API usage for classes that were renamed/changed.
 */
public class Main {

    public static void main(String[] args) throws IOException {
        if (args.length < 1) {
            System.err.println("Usage: java github.chains.Main <source-directory>");
            System.exit(1);
        }

        Path sourceDir = Paths.get(args[0]);
        if (!Files.isDirectory(sourceDir)) {
            System.err.println("Error: " + sourceDir + " is not a directory");
            System.exit(1);
        }

        System.out.println("Processing Java files in: " + sourceDir);

        try (Stream<Path> paths = Files.walk(sourceDir)) {
            int fixed = 0;
            for (Path javaFile : paths.filter(Files::isRegularFile)
                    .filter(p -> p.toString().endsWith(".java")).toList()) {
                if (fixFile(javaFile)) {
                    fixed++;
                    System.out.println("Fixed: " + javaFile);
                }
            }
            System.out.println("Total files fixed: " + fixed);
        }
    }

    private static boolean fixFile(Path javaFile) throws IOException {
        String content = Files.readString(javaFile);
        String original = content;

        // Fix import paths - LengthOf is in scalar package
        content = content.replace(
            "import org.cactoos.iterable.LengthOf;",
            "import org.cactoos.scalar.LengthOf;"
        );
        // Fix collection package imports to iterable
        content = content.replace(
            "import org.cactoos.collection.Filtered;",
            "import org.cactoos.iterable.Filtered;"
        );
        content = content.replace(
            "import org.cactoos.collection.CollectionOf;",
            "import java.util.ArrayList;"
        );
        // Fix text class names (SplitText -> Split, etc.)
        content = content.replace(
            "import org.cactoos.text.SplitText;",
            "import org.cactoos.text.Split;"
        );
        content = content.replace(
            "import org.cactoos.text.JoinedText;",
            "import org.cactoos.text.Joined;"
        );
        content = content.replace(
            "import org.cactoos.text.TrimmedText;",
            "import org.cactoos.text.Trimmed;"
        );
        // Fix scalar class names (removed "Scalar" suffix)
        content = content.replace(
            "import org.cactoos.scalar.StickyScalar;",
            "import org.cactoos.scalar.Sticky;"
        );
        content = content.replace(
            "import org.cactoos.scalar.SolidScalar;",
            "import org.cactoos.scalar.Solid;"
        );
        content = content.replace(
            "import org.cactoos.scalar.IoCheckedScalar;",
            "import org.cactoos.scalar.IoChecked;"
        );
        content = content.replace(
            "import org.cactoos.func.IoCheckedScalar;",
            "import org.cactoos.scalar.IoChecked;"
        );
        // Fix RandomText to Randomized
        content = content.replace(
            "import org.cactoos.text.RandomText;",
            "import org.cactoos.text.Randomized;"
        );
        // Fix CheckedScalar and UncheckedScalar (removed "Scalar" suffix)
        content = content.replace(
            "import org.cactoos.scalar.CheckedScalar;",
            "import org.cactoos.scalar.Checked;"
        );
        content = content.replace(
            "import org.cactoos.scalar.UncheckedScalar;",
            "import org.cactoos.scalar.Unchecked;"
        );
        // Fix IoCheckedFunc
        content = content.replace(
            "import org.cactoos.func.IoCheckedFunc;",
            "import org.cactoos.func.IoCheckedBiFunc;"
        );

        // Fix code usages - class instantiations
        content = content.replace("new SplitText(", "new Split(");
        content = content.replace("new JoinedText(", "new Joined(");
        content = content.replace("new TrimmedText(", "new Trimmed(");
        content = content.replace("new StickyScalar<>(", "new Sticky<>(");
        content = content.replace("new SolidScalar<>(", "new Solid<>(");
        content = content.replace("new CheckedScalar<>(", "new Checked<>(");
        content = content.replace("new UncheckedScalar<>(", "new Unchecked<>(");
        content = content.replace("new IoCheckedScalar<>(", "new IoChecked<>(");
        content = content.replace("new RandomText()", "new Randomized()");

        // Fix type references
        content = content.replace("IoCheckedScalar<", "IoChecked<");
        content = content.replace("IoCheckedFunc<", "IoCheckedBiFunc<");

        // Fix LengthOf.intValue() - in 0.55 LengthOf returns Long, so we need .value().intValue()
        // But the code has new LengthOf(...).intValue() which should be new LengthOf(...).value().intValue()
        // However, looking at the actual usage pattern, we should convert .intValue() to .value().intValue()
        content = content.replace("new LengthOf(", "new LengthOf(");
        content = content.replace(".intValue()", ".value().intValue()");

        if (!content.equals(original)) {
            Files.writeString(javaFile, content);
            return true;
        }
        return false;
    }
}

